import React, { useContext } from "react";
import { Routes, Route } from "react-router-dom";
import Topbar from "./TopBar";
import WatchList from "./WatchList";
import Summary from "./Summary";
import Orders from "./Orders";
import Holdings from "./Holdings";
import Positions from "./Positions";
import Funds from "./Funds"; 
import BuyActionWindow from "./BuyActionWindow";
import { GeneralContext } from "./GeneralContext";

const Dashboard = () => {
  // 2. UPDATED: Destructure windowMode alongside isBuyWindowOpen
  const { isBuyWindowOpen, windowMode } = useContext(GeneralContext);

  return (
    <div className="main-layout">
      {/* Renders once here, anchoring the menu at the very top */}
      <Topbar />

      {/* Screen splits horizontally below the Topbar navigation menu */}
      <div className="dashboard-container">
        <WatchList />

        <div className="content">
          <Routes>
            <Route path="/" element={<Summary />} />
            <Route path="/orders" element={<Orders />} />
            <Route path="/holdings" element={<Holdings />} />
            <Route path="/positions" element={<Positions />} />

            {/* 3. ADDED: Mapped the sub-routing match token for the Funds page */}
            <Route path="/funds" element={<Funds />} />
          </Routes>
        </div>
      </div>

      {/* 4. UPDATED: Pass the dynamic windowMode state ("BUY" or "SELL") to the window */}
      {isBuyWindowOpen && <BuyActionWindow mode={windowMode} />}
    </div>
  );
};

export default Dashboard;
